import React from 'react';

const Footer = () => {
  return (
    <footer style={{
      background: 'linear-gradient(135deg, #ffffff 0%, #f5f7fa 100%)',
      padding: '1rem 0',
      borderTop: '1px solid rgba(0, 0, 0, 0.05)',
      marginTop: 'auto',
      position: 'fixed',
      bottom: 0,
      left: 0,
      right: 0,
      zIndex: 1000
    }}>
      <div className="container-fluid">
        <div className="d-flex justify-content-center align-items-center">
          <div style={{
            display: 'flex',
            alignItems: 'center',
            gap: '8px',
            color: '#666',
            fontSize: '0.9rem',
            fontWeight: 500
          }}>
            <img 
              src="/Logo/LSlogo.png" 
              alt="Loyalstring" 
              style={{ 
                height: '20px',
                opacity: 0.8
              }} 
            />
            <span>© 2025 Loyalstring Pvt Ltd. All rights reserved.</span>
          </div>
        </div>
      </div>
    </footer>
  );
};

export default Footer;
